import{_ as e,o as l,c as d,ag as n}from"./chunks/framework.DGzMGr_a.js";const f=JSON.parse('{"title":"PPAP 生产件批准程序","description":"","frontmatter":{},"headers":[],"relativePath":"tools/ppap.md","filePath":"tools/ppap.md","lastUpdated":1782656455000}'),a={name:"tools/ppap.md"};function r(s,t,i,g,o,x){return l(),d("div",null,[...t[0]||(t[0]=[n('<h1 id="ppap-生产件批准程序" tabindex="-1">PPAP 生产件批准程序 <a class="header-anchor" href="#ppap-生产件批准程序" aria-label="Permalink to &quot;PPAP 生产件批准程序&quot;">​</a></h1><p>PPAP（Production Part Approval Process，生产件批准程序）是用于确认供应商的生产过程是否已准备好批量生产、是否能持续满足客户所有要求的标准化流程。PPAP 起源于美国汽车工业，现已被 IATF 16949 体系广泛采用，成为全球制造业供应链质量管理的核心工具。</p><h2 id="ppap-的目的" tabindex="-1">PPAP 的目的 <a class="header-anchor" href="#ppap-的目的" aria-label="Permalink to &quot;PPAP 的目的&quot;">​</a></h2><p>PPAP 的核心目标是在<strong>正式量产前</strong>验证以下事项：</p><ol><li><strong>设计完整性</strong> — 产品和设计记录满足客户要求</li><li><strong>过程能力</strong> — 生产工艺具备稳定满足规格的能力</li><li><strong>测量系统可靠性</strong> — 检验/测试方法经过 MSA 验证</li><li><strong>供应链可追溯</strong> — 所有分供方件也得到同等管控</li><li><strong>批量一致性</strong> — 试产样件能代表批量生产的质量水平</li></ol><h2 id="_18-项提交要素" tabindex="-1">18 项提交要素 <a class="header-anchor" href="#_18-项提交要素" aria-label="Permalink to &quot;18 项提交要素&quot;">​</a></h2><p>PPAP 第 4 版要求提交以下 18 项要素：</p><table tabindex="0"><thead><tr><th style="text-align:center;">编号</th><th style="text-align:left;">要素</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td style="text-align:left;">设计记录</td><td style="text-align:left;">产品图纸、数模、技术规范</td></tr><tr><td style="text-align:center;">2</td><td style="text-align:left;">工程变更文件</td><td style="text-align:left;">授权变更的工程批准文件</td></tr><tr><td style="text-align:center;">3</td><td style="text-align:left;">DFMEA</td><td style="text-align:left;">设计失效模式分析</td></tr><tr><td style="text-align:center;">4</td><td style="text-align:left;">过程流程图</td><td style="text-align:left;">生产工艺步骤与检验点</td></tr><tr><td style="text-align:center;">5</td><td style="text-align:left;">PFMEA</td><td style="text-align:left;">过程失效模式分析</td></tr><tr><td style="text-align:center;">6</td><td style="text-align:left;">控制计划</td><td style="text-align:left;">各工序控制方法、频次、反应计划</td></tr><tr><td style="text-align:center;">7</td><td style="text-align:left;">MSA 结果</td><td style="text-align:left;">量具重复性与再现性研究</td></tr><tr><td style="text-align:center;">8</td><td style="text-align:left;">尺寸结果</td><td style="text-align:left;">全尺寸检测报告</td></tr><tr><td style="text-align:center;">9</td><td style="text-align:left;">材料/性能测试结果</td><td style="text-align:left;">材质报告、性能试验报告</td></tr><tr><td style="text-align:center;">10</td><td style="text-align:left;">初始过程能力研究</td><td style="text-align:left;">Cp/Cpk 或 Ppk 分析</td></tr><tr><td style="text-align:center;">11</td><td style="text-align:left;">实验室资质</td><td style="text-align:left;">测试实验室的认证范围</td></tr><tr><td style="text-align:center;">12</td><td style="text-align:left;">外观批准报告 (AAR)</td><td style="text-align:left;">颜色、纹理、光泽等外观认可</td></tr><tr><td style="text-align:center;">13</td><td style="text-align:left;">散装材料要求检查表</td><td style="text-align:left;">仅适用于散装材料（如化学品）</td></tr><tr><td style="text-align:center;">14</td><td style="text-align:left;">样品产品</td><td style="text-align:left;">提交代表性样件</td></tr><tr><td style="text-align:center;">15</td><td style="text-align:left;">标准样品</td><td style="text-align:left;">作为比较基准的封样</td></tr><tr><td style="text-align:center;">16</td><td style="text-align:left;">检查辅具</td><td style="text-align:left;">检具/量具的验证记录</td></tr><tr><td style="text-align:center;">17</td><td style="text-align:left;">客户特殊要求</td><td style="text-align:left;">客户指定的额外要求</td></tr><tr><td style="text-align:center;">18</td><td style="text-align:left;">零件提交保证书 (PSW)</td><td style="text-align:left;">PPAP 最终签署文件</td></tr></tbody></table><h2 id="_5-个提交等级" tabindex="-1">5 个提交等级 <a class="header-anchor" href="#_5-个提交等级" aria-label="Permalink to &quot;5 个提交等级&quot;">​</a></h2><p>客户根据产品风险和供应商成熟度指定提交等级：</p><table tabindex="0"><thead><tr><th style="text-align:center;">等级</th><th style="text-align:left;">名称</th><th style="text-align:left;">说明</th><th style="text-align:left;">典型场景</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>Level 1</strong></td><td style="text-align:left;">仅 PSW</td><td style="text-align:left;">仅提交零件提交保证书</td><td style="text-align:left;">低风险变更、成熟供应商</td></tr><tr><td style="text-align:center;"><strong>Level 2</strong></td><td style="text-align:left;">PSW + 样品</td><td style="text-align:left;">提交 PSW + 有限支持数据 + 样品</td><td style="text-align:left;">简单零件、小批量</td></tr><tr><td style="text-align:center;"><strong>Level 3</strong></td><td style="text-align:left;">全部要素</td><td style="text-align:left;"><strong>提交全部 18 项要素</strong>（最常用）</td><td style="text-align:left;">新零件、新供应商（默认等级）</td></tr><tr><td style="text-align:center;"><strong>Level 4</strong></td><td style="text-align:left;">客户指定</td><td style="text-align:left;">由客户定义需要提交的要素</td><td style="text-align:left;">特殊合同要求</td></tr><tr><td style="text-align:center;"><strong>Level 5</strong></td><td style="text-align:left;">PSW + 现场评审</td><td style="text-align:left;">提交 PSW + 供应商现场评审资料</td><td style="text-align:left;">高风险零件、新供应商的首次提交</td></tr></tbody></table><blockquote><p><strong>注</strong>：如果客户未指定提交等级，供应商默认按 <strong>Level 3</strong> 准备全部 18 项要素。</p></blockquote><h2 id="关键-重要-一般特性定义" tabindex="-1">关键/重要/一般特性定义 <a class="header-anchor" href="#关键-重要-一般特性定义" aria-label="Permalink to &quot;关键/重要/一般特性定义&quot;">​</a></h2><p>PPAP 要求对产品特性进行分类管理：</p><table tabindex="0"><thead><tr><th style="text-align:left;">特性类别</th><th style="text-align:left;">定义</th><th style="text-align:left;">管控要求</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>关键特性</strong> (Critical, ⚠)</td><td style="text-align:left;">涉及安全或法规符合性，失效会导致人身伤害或法规违反</td><td style="text-align:left;">100% 检验或防错控制，Ppk ≥ 1.67</td></tr><tr><td style="text-align:left;"><strong>重要特性</strong> (Significant, ◆)</td><td style="text-align:left;">影响功能、配合、性能，失效会导致功能丧失或重大客户抱怨</td><td style="text-align:left;">SPC 监控，Ppk ≥ 1.33</td></tr><tr><td style="text-align:left;"><strong>一般特性</strong> (General)</td><td style="text-align:left;">不影响功能和安全的一般外观或尺寸要求</td><td style="text-align:left;">常规检验，Ppk ≥ 1.00</td></tr></tbody></table><h2 id="初始过程能力研究要求" tabindex="-1">初始过程能力研究要求 <a class="header-anchor" href="#初始过程能力研究要求" aria-label="Permalink to &quot;初始过程能力研究要求&quot;">​</a></h2><p>PPAP 要求在新项目量产前进行初始过程能力研究（Initial Process Capability Study）：</p><ul><li><strong>取样方式</strong>：连续生产 100~300 件（通常 125 件），涵盖正常生产中可能出现的变异</li><li><strong>稳定性前提</strong>：分析过程能力前，必须先确认过程处于统计受控状态（控制图无异常）</li><li><strong>评估标准</strong>： <ul><li><strong>Ppk ≥ 1.67</strong> — 过程能力满足要求，可批准量产</li><li><strong>1.33 ≤ Ppk &lt; 1.67</strong> — 过程能力可接受，但需加强监控和持续改进</li><li><strong>Ppk &lt; 1.33</strong> — 过程能力不足，必须制定和实施改进计划，不得直接批准量产</li></ul></li><li><strong>长期追踪</strong>：PPAP 批准后，供应商需在量产中持续监控过程能力，定期向客户提交 Cp/Cpk 报告</li></ul><blockquote><p><strong>PPAP 是一个流程，不是一个事件。</strong> 它贯穿于新项目开发的整个过程，从设计评审到工装验证再到批量试产。成功的 PPAP 不是靠一次性的资料准备，而是靠从一开始就嵌入到项目各阶段的质量策划和过程控制。</p></blockquote>',19)])])}const P=e(a,[["render",r]]);export{f as __pageData,P as default};
